from dataclasses import dataclass
from typing import List, Dict
from enum import Enum

class Phase(Enum):
    RESEARCH = 1
    POC = 2
    PILOT = 3
    PRODUCTION = 4

@dataclass
class CaseStudy:
    name: str
    institution: str
    domain: str
    phase: Phase
    investment_millions: float
    team_size: int

class CaseAnalyzer:
    def __init__(self):
        self.studies: List[CaseStudy] = []

    def add_study(self, study: CaseStudy):
        self.studies.append(study)

    def by_domain(self) -> Dict[str, List[CaseStudy]]:
        result = {}
        for s in self.studies:
            if s.domain not in result:
                result[s.domain] = []
            result[s.domain].append(s)
        return result

    def average_investment_by_phase(self) -> Dict[str, float]:
        by_phase = {}
        for phase in Phase:
            phase_studies = [s for s in self.studies if s.phase == phase]
            if phase_studies:
                by_phase[phase.name] = sum(s.investment_millions for s in phase_studies) / len(phase_studies)
        return by_phase

    def most_advanced(self) -> CaseStudy:
        if not self.studies:
            return None
        return max(self.studies, key=lambda s: s.phase.value)

