from dataclasses import dataclass
from typing import List, Dict

@dataclass
class Lesson:
    text: str
    category: str
    importance: int

class LessonsExtractor:
    def __init__(self):
        self.lessons: List[Lesson] = []

    def add_lesson(self, lesson: Lesson):
        self.lessons.append(lesson)

    def by_category(self) -> Dict[str, List[str]]:
        result = {}
        for l in self.lessons:
            if l.category not in result:
                result[l.category] = []
            result[l.category].append(l.text)
        return result

    def priority_list(self) -> List[Dict]:
        sorted_lessons = sorted(self.lessons, key=lambda x: x.importance, reverse=True)
        return [{'lesson': l.text, 'category': l.category, 'importance': l.importance} for l in sorted_lessons]

    def generate_checklist(self, min_importance: int = 4) -> List[str]:
        return [l.text for l in self.lessons if l.importance >= min_importance]

