from dataclasses import dataclass
from typing import List, Dict
import numpy as np

@dataclass
class ProjectMetrics:
    name: str
    phase_progress: float
    technical_score: float
    team_score: float
    partnership_score: float

class SuccessEvaluator:
    def __init__(self):
        self.projects: List[ProjectMetrics] = []
        self.weights = {'phase': 0.3, 'technical': 0.3, 'team': 0.2, 'partnership': 0.2}

    def add_project(self, project: ProjectMetrics):
        self.projects.append(project)

    def composite_score(self, project: ProjectMetrics) -> float:
        return (
            self.weights['phase'] * project.phase_progress +
            self.weights['technical'] * project.technical_score +
            self.weights['team'] * project.team_score +
            self.weights['partnership'] * project.partnership_score
        )

    def rank_projects(self) -> List[Dict]:
        scored = [(p, self.composite_score(p)) for p in self.projects]
        sorted_projects = sorted(scored, key=lambda x: x[1], reverse=True)
        return [{'name': p.name, 'score': round(s, 3)} for p, s in sorted_projects]

    def identify_gaps(self, project: ProjectMetrics) -> Dict[str, float]:
        if not self.projects:
            return {}

        avg_phase = np.mean([p.phase_progress for p in self.projects])
        avg_tech = np.mean([p.technical_score for p in self.projects])
        avg_team = np.mean([p.team_score for p in self.projects])
        avg_partner = np.mean([p.partnership_score for p in self.projects])

        return {
            'phase_gap': avg_phase - project.phase_progress,
            'technical_gap': avg_tech - project.technical_score,
            'team_gap': avg_team - project.team_score,
            'partnership_gap': avg_partner - project.partnership_score
        }
